sys_script.script:
(function executeRule(current, previous /*null when async*/) {

	/*
		When (after) a Configured Action is created, find all Action Package Parameters
		 associated with the selected Action Package, and create records in the
		 "Configured Action Parameter" table for each.
	*/

	var packageParamKey;
	var currentConfiguredActionID = current.getUniqueValue(); //The current "Configured Action" record.
	var selectedPackageID = current.getValue('action_package'); //Selected action package
	var grConfiguredPackageParam = new GlideRecord('x_taniu_tan_core_configured_action_parameter');
	var grPackageParam = new GlideRecord('x_taniu_tan_core_tanium_package_parameter');

	//If a package has somehow not been selected (which should be impossible, but you never
	// know), then warn.
	if (!selectedPackageID) {
		gs.warn('The record in table ' + current.getTableName() + ' has been created or updated without any Tanium Action Package selected. This should not be possible. You may want to investigate.');
		return;
		//We could abort the update here, but since this should be impossible, we don't want to
		// risk breaking something.
	}

	grPackageParam.addQuery('package', selectedPackageID);
	grPackageParam.addNotNullQuery('key');
	grPackageParam.query();

	while (grPackageParam.next()) {
		packageParamKey = grPackageParam.getValue('key');
		grConfiguredPackageParam.initialize();

		grConfiguredPackageParam.setValue(
			'package_parameter',
			grPackageParam.getUniqueValue()
		);
		grConfiguredPackageParam.setValue(
			'configured_action',
			currentConfiguredActionID
		);
		grConfiguredPackageParam.setValue(
			'key',
			packageParamKey
		);

		grConfiguredPackageParam.insert();
	}

})(current, previous);
